examples.fromCode:
function divide(a: number, b: number): number {
  if (b === 0) throw new Error("div by zero");
  return a / b;
}

examples.toCode:
import "errors"

func divide(a, b float64) (float64, error) {
    if b == 0 {
        return 0, errors.New("div by zero")
    }
    return a / b, nil
}
